def list_files(folder_path: str, recursive: bool = True, file_filter: str = "") -> list:
    """
    遍历文件夹获取文件列表。

    参数:
        folder_path (str): 要遍历的文件夹路径
        recursive (bool): 是否递归遍历子文件夹，默认 True
        file_filter (str): 文件扩展名过滤，如 "*.txt" 或 "*.jpg;*.png"，空表示不过滤

    返回:
        list: 文件路径列表
    """
    import os
    try:
        if not os.path.exists(folder_path):
            print(f"错误：文件夹不存在 - {folder_path}")
            return []

        if not os.path.isdir(folder_path):
            print(f"错误：路径不是文件夹 - {folder_path}")
            return []

        # 解析文件类型过滤
        filters = [e.strip().lower() for e in file_filter.split(";") if e.strip()] if file_filter else []
        file_list = []

        if recursive:
            # 递归遍历
            for root, dirs, files in os.walk(folder_path):
                for f in files:
                    if filters:
                        ext = os.path.splitext(f)[1].lower()
                        if not any(ext == e or ext == f".{e.lstrip('*')}" for e in filters):
                            continue
                    file_list.append(os.path.join(root, f))
        else:
            # 仅遍历当前目录
            for f in os.listdir(folder_path):
                fp = os.path.join(folder_path, f)
                if os.path.isfile(fp):
                    if filters:
                        ext = os.path.splitext(f)[1].lower()
                        if not any(ext == e or ext == f".{e.lstrip('*')}" for e in filters):
                            continue
                    file_list.append(fp)

        print(f"遍历完成，共找到 {len(file_list)} 个文件")
        return file_list
    except Exception as e:
        print(f"错误：遍历文件夹失败 - {e}")
        return []

def read_word(file_path: str, read_type: str = "full") -> str:
    """
    读取 Word 文档内容。

    参数:
        file_path (str): Word 文件路径 (.docx)
        read_type (str): "full" 全文、"paragraphs" 段落列表、"tables" 表格列表

    返回:
        str: 文档内容（全文为字符串，段落/表格为 JSON 字符串）
    """
    import os
    import json
    from docx import Document
    try:
        if not os.path.exists(file_path):
            print(f"错误：文件不存在 - {file_path}")
            return ""

        doc = Document(file_path)

        if read_type == "full":
            content = "\n".join([p.text for p in doc.paragraphs])
            return content
        elif read_type == "paragraphs":
            return json.dumps([p.text for p in doc.paragraphs], ensure_ascii=False)
        elif read_type == "tables":
            tables_data = []
            for table in doc.tables:
                table_data = [[c.text for c in row.cells] for row in table.rows]
                tables_data.append(table_data)
            return json.dumps(tables_data, ensure_ascii=False)
        return ""
    except Exception as e:
        print(f"错误：读取 Word 失败 - {e}")
        return ""

def aggregate_data(input_data: list, group_field: str, agg_field: str, agg_func: str = "count") -> list:
    """
    对数据进行分组聚合。

    参数:
        input_data (list): 输入数据列表（字典列表）
        group_field (str): 分组依据字段
        agg_field (str): 要聚合的字段
        agg_func (str): 聚合方式
            - "count": 计数
            - "sum": 求和
            - "avg": 平均值
            - "max": 最大值
            - "min": 最小值

    返回:
        list: 聚合结果列表
    """
    try:
        if not input_data:
            return []

        groups = {}
        for item in input_data:
            if isinstance(item, dict):
                k = item.get(group_field)
                if k not in groups:
                    groups[k] = []
                groups[k].append(item.get(agg_field))

        result = []
        for k, vals in groups.items():
            if agg_func == "count":
                v = len(vals)
            elif agg_func == "sum":
                v = sum(x for x in vals if isinstance(x, (int, float)))
            elif agg_func == "avg":
                nums = [x for x in vals if isinstance(x, (int, float))]
                v = sum(nums) / len(nums) if nums else 0
            elif agg_func == "max":
                v = max(x for x in vals if isinstance(x, (int, float))) if any(isinstance(x, (int, float)) for x in vals) else None
            elif agg_func == "min":
                v = min(x for x in vals if isinstance(x, (int, float))) if any(isinstance(x, (int, float)) for x in vals) else None
            else:
                v = len(vals)

            result.append({group_field: k, f"{agg_field}_{agg_func}": v})

        print(f"数据聚合完成，共 {len(result)} 组")
        return result
    except Exception as e:
        print(f"错误：数据聚合失败 - {e}")
        return []

def format_date(date_str: str = "", input_format: str = "", output_format: str = "%Y-%m-%d") -> str:
    """
    格式化日期字符串。

    参数:
        date_str (str): 日期字符串，空则使用当前时间
        input_format (str): 输入日期的格式，空则自动识别
        output_format (str): 输出格式，如 "%Y-%m-%d %H:%M:%S"

    返回:
        str: 格式化后的日期字符串
    """
    from datetime import datetime
    try:
        if not date_str:
            dt = datetime.now()
        elif input_format:
            dt = datetime.strptime(date_str, input_format)
        else:
            for fmt in ["%Y-%m-%d", "%Y/%m/%d", "%Y-%m-%d %H:%M:%S", "%Y%m%d"]:
                try:
                    dt = datetime.strptime(date_str, fmt)
                    break
                except:
                    continue
            else:
                return ""
        return dt.strftime(output_format)
    except Exception as e:
        print(f"错误：日期格式化失败 - {e}")
        return ""
